703: func (b *throttledLogger) attemptToLog() (klog.Level, bool) {
704: 	for _, setting := range b.settings {
705: 		if bool(klog.V(setting.logLevel).Enabled()) {
706: 			// Return early without write locking if possible.
707: 			if func() bool {
708: 				setting.lock.RLock()
709: 				defer setting.lock.RUnlock()
710: 				return b.clock.Since(setting.lastLogTime) >= setting.minLogInterval
711: 			}() {
712: 				setting.lock.Lock()
713: 				defer setting.lock.Unlock()
714: 				if b.clock.Since(setting.lastLogTime) >= setting.minLogInterval {
715: 					setting.lastLogTime = b.clock.Now()
716: 					return setting.logLevel, true
717: 				}
718: 			}
719: 			return -1, false
720: 		}
721: 	}
722: 	return -1, false
723: }
