740: func (r *Request) watchInternal(ctx context.Context) (watch.Interface, runtime.Decoder, error) {
741: 	if r.body == nil {
742: 		logBody(ctx, 2, "Request Body", r.bodyBytes)
743: 	}
744: 
745: 	// We specifically don't want to rate limit watches, so we
746: 	// don't use r.rateLimiter here.
747: 	if r.err != nil {
748: 		return nil, nil, r.err
749: 	}
750: 
751: 	client := r.c.Client
752: 	if client == nil {
753: 		client = http.DefaultClient
754: 	}
755: 
756: 	isErrRetryableFunc := func(request *http.Request, err error) bool {
757: 		// The watch stream mechanism handles many common partial data errors, so closed
758: 		// connections can be retried in many cases.
759: 		if net.IsProbableEOF(err) || net.IsTimeout(err) {
760: 			return true
761: 		}
762: 		return false
763: 	}
764: 	retry := r.retryFn(r.maxRetries)
765: 	url := r.URL().String()
766: 	for {
767: 		if err := retry.Before(ctx, r); err != nil {
768: 			return nil, nil, retry.WrapPreviousError(err)
769: 		}
770: 
771: 		req, err := r.newHTTPRequest(ctx)
772: 		if err != nil {
773: 			return nil, nil, err
774: 		}
775: 
776: 		resp, err := client.Do(req)
777: 		retry.After(ctx, r, resp, err)
778: 		if err == nil && resp.StatusCode == http.StatusOK {
779: 			return r.newStreamWatcher(resp)
780: 		}
781: 
782: 		done, transformErr := func() (bool, error) {
783: 			defer readAndCloseResponseBody(resp)
784: 
785: 			if retry.IsNextRetry(ctx, r, req, resp, err, isErrRetryableFunc) {
786: 				return false, nil
787: 			}
788: 
789: 			if resp == nil {
790: 				// the server must have sent us an error in 'err'
791: 				return true, nil
792: 			}
793: 			result := r.transformResponse(ctx, resp, req)
794: 			if err := result.Error(); err != nil {
795: 				return true, err
796: 			}
797: 			return true, fmt.Errorf("for request %s, got status: %v", url, resp.StatusCode)
798: 		}()
799: 		if done {
800: 			if isErrRetryableFunc(req, err) {
801: 				return watch.NewEmptyWatch(), nil, nil
802: 			}
803: 			if err == nil {
804: 				// if the server sent us an HTTP Response object,
805: 				// we need to return the error object from that.
806: 				err = transformErr
807: 			}
808: 			return nil, nil, retry.WrapPreviousError(err)
809: 		}
810: 	}
811: }
